@app.route('/api/users', methods=['POST'])
def create_user():
    try:
        # Secure input validation
        user_data = validate_input(request.get_json())
        
        # APM transaction for database operation
        with apm_client.capture_span('create_user_db'):
            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO users (name, email) VALUES (?, ?)",
                (user_data.get('name'), user_data.get('email'))
            )
            conn.commit()
            user_id = cursor.lastrowid
            conn.close()
        
        return jsonify({'id': user_id, 'message': 'User created successfully'}), 201
        
    except Exception as e:
        apm_client.capture_exception()
        return jsonify({'error': str(e)}), 500

@app.route('/api/users/<int:user_id>', methods=['GET'])
def get_user(user_id):
    try:
        # APM transaction for database operation
        with apm_client.capture_span('get_user_db'):
            conn = get_db_connection()
            user = conn.execute(
                "SELECT * FROM users WHERE id = ?", 
                (user_id,)
            ).fetchone()
            conn.close()
            
            if user is None:
                return jsonify({'error': 'User not found'}), 404
                
            return jsonify(dict(user)), 200
            
    except Exception as e:
        apm_client.capture_exception()
        return jsonify({'error': str(e)}), 500

